    headers = await get_auth_headers(method, path)
    if extra_headers:
        headers.update(extra_headers)
    logger.info(f"{method} {url}")
    async with httpx.AsyncClient(timeout=30.0) as client:
        if query_params:
            query_params = {k: v for k, v in query_params.items() if v is not None}
        kwargs: Dict[str, Any] = {"headers": headers, "params": query_params}
        if body is not None and method.upper() not in ["GET", "DELETE"]:
            kwargs["data" if content_type == "multipart/form-data" else "json"] = body
        try:
            resp = await client.request(method, url, **kwargs)
            resp.raise_for_status()
            try:
                return resp.json()
            except Exception:
                return resp.text
        except httpx.HTTPStatusError as e:
            return {"error": f"API returned {e.response.status_code}", "details": e.response.text}
        except Exception as e:
            return {"error": str(e)}



