from starlette.applications import Starlette
from starlette.responses import JSONResponse, Response
from starlette.routing import Route
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.requests import Request as _R

class _NoCacheMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        resp = await call_next(request)
        if request.url.path in ("/sse", "/messages", "/messages/"):
            resp.headers["Cache-Control"] = "no-cache"
            resp.headers["Connection"] = "keep-alive"
            resp.headers["X-Accel-Buffering"] = "no"
        return resp

class _HubSecurityMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        # Allow health checks and root
        if request.url.path in ("/", "/health"):
            return await call_next(request)
        
        # Check for openplug.ai Key in Header or Query Param
        hub_key = request.headers.get("X-openplug.ai-Key") or request.query_params.get("apikey")
        
        # Allow THE Hub's internal key (for insights and management)
        if hub_key == "openplug.ai_internal_access":
            return await call_next(request)
        
        # Check for valid key
        if not hub_key:
            return JSONResponse({"error": "Unauthorized: Missing X-openplug.ai-Key (Hub Bypass Detected)"}, status_code=401)
            
        return await call_next(request)

try:
    from mcp.server.sse import SseServerTransport
    _transport = SseServerTransport("/messages/")

    # GET /sse — SSE streaming endpoint
    async def _sse_endpoint(request: _R):
        _inner = getattr(mcp, '_mcp_server', None) or getattr(mcp, 'server', None) or mcp
        async with _transport.connect_sse(request.scope, request.receive, request._send) as (r, w):
            await _inner.run(r, w, _inner.create_initialization_options(), raise_exceptions=False)
        return Response()

    # POST /sse — Streamable HTTP (direct tool dispatch, no SSE overhead)
    async def _sse_post_endpoint(request: _R):
        raw = await request.body()
        try:
            body = json.loads(raw)
            method = body.get("method")
            if method == "initialize":
                return JSONResponse({
                    "server": getattr(mcp, "name", "mcp-server"),
                    "capabilities": {"tools": True, "resources": False, "prompts": False}
                })
            elif method == "tools/list":
                tools_list = []
                try:
                    for t in getattr(mcp, "_tools", {}).values():
                        tools_list.append({"name": t.name, "description": getattr(t, "description", "")})
                except Exception:
                    pass
                return JSONResponse({"tools": tools_list})
            elif method == "tools/call":
                params = body.get("params", {})
                name = params.get("name")
                args = params.get("arguments", {})
                _start = time.perf_counter()
                _status, _error = "success", None
                try:
                    sanitized = "".join(c if c.isalnum() else "_" for c in name)
                    if sanitized and sanitized[0].isdigit():
                        sanitized = "t_" + sanitized
                    tool_fn = globals().get(sanitized)
                    if tool_fn:
                        res = await tool_fn(**args)
                        return JSONResponse({"content": [{"type": "text", "text": str(res)}]})
                    else:
                        raise ValueError(f"Tool '{name}' not found")
                except Exception as e:
                    _status, _error = "error", str(e)
                    return JSONResponse({"isError": True, "content": [{"type": "text", "text": str(e)}]})
                finally:
                    _dur = (time.perf_counter() - _start) * 1000
                    await _post_insight(name or "unknown", _status, _dur, _error, len(raw), 0)
            return JSONResponse({"error": "Unsupported method"}, status_code=400)
        except Exception as e:
            return JSONResponse({"error": str(e)}, status_code=500)

    # POST /messages — raw SSE transport handler
    async def _messages_endpoint(request: _R):
        raw = await request.body()
        _start = time.perf_counter()
        _tool_name, _is_tool_call = None, False
        try:
            _msgs = json.loads(raw)
            if isinstance(_msgs, dict):
                _msgs = [_msgs]
            for _m in _msgs:
                if _m.get("method") == "tools/call":
                    _is_tool_call = True
                    _tool_name = (_m.get("params") or {}).get("name", "unknown")
                    break
        except Exception:
            pass
        _status, _error = "success", None
        try:
            _send = getattr(request, "_send", None)
            if _send:
                async def _replay():
                    return {"type": "http.request", "body": raw, "more_body": False}
                await _transport.handle_post_message(request.scope, _replay, _send)
        except Exception as _exc:
            _status, _error = "error", str(_exc)
        finally:
            if _is_tool_call and _tool_name:
                _dur = (time.perf_counter() - _start) * 1000
                await _post_insight(_tool_name, _status, _dur, _error, len(raw), 0)
        return Response(status_code=202)

    app = Starlette(routes=[
        Route("/",            _root_handler),
        Route("/sse",         _sse_endpoint,      methods=["GET"]),
        Route("/sse",         _sse_post_endpoint, methods=["POST"]),
        Route("/messages/",   _messages_endpoint, methods=["POST"]),
        Route("/messages",    _messages_endpoint, methods=["POST"]),
        Route("/{path:path}", _root_handler),
    ])
    app.add_middleware(_NoCacheMiddleware)
    app.add_middleware(_HubSecurityMiddleware)
    logger.info("MCP server ready.")

except Exception as _boot_err:
    import traceback as _tb
    logger.error(f"FATAL: {_boot_err}\n{_tb.format_exc()}")
    async def _err(r): return JSONResponse({"status": "error", "detail": str(_boot_err)}, status_code=500)
    app = Starlette(routes=[Route("/", _err), Route("/{path:path}", _err)])
